  1→import { useState, useEffect, useRef, useCallback } from "react";
  2→import { invoke } from "@tauri-apps/api/core";
  3→import { Sidebar } from "./features/repos/Sidebar";
  4→import { useReposQuery } from "./hooks/use-tauri-query";
  5→import { TitleBar } from "./components/TitleBar";
  6→import { TabBar } from "./components/TabBar";
  7→import { CheckpointList } from "./features/checkpoints/CheckpointList";
  8→import { TranscriptView } from "./features/transcripts/TranscriptView";
  9→import { DiffView, BranchDiffView } from "./features/diff/DiffView";
 10→import { CheckpointInsightsContainer } from "./features/insights/CheckpointInsightsContainer";
 11→import { BranchInsightsContainer } from "./features/insights/BranchInsightsContainer";
 12→import { BranchDebugContainer } from "./features/debug/BranchDebugContainer";
 13→import { CheckpointDebugContainer } from "./features/debug/CheckpointDebugContainer";
 14→import { TerminalPanel } from "./features/terminal/TerminalPanel";
 15→import type { TerminalPanelHandle } from "./features/terminal/TerminalPanel";
 16→import { createBranchTab, createWorktreeTab } from "./features/repos/tab-state";
 17→import { DEFAULT_SIDEBAR_WIDTH, clampSidebarWidth } from "./features/repos/sidebar-width.ts";
 18→import { planWorktreeDeletionCleanup } from "./features/repos/worktree-delete-state.ts";
 19→import {
 20→  collectWorkspaceSurfaceIds,
 21→  createTerminalWorkspace,
 22→  type TerminalWorkspace,
 23→  type WorkspaceUpdate,
 24→} from "./features/terminal/workspace";
 25→import {
 26→  createTerminalPanelVisibility,
 27→  isTerminalPanelOpen,
 28→  setTerminalPanelOpen,
 29→  syncTerminalPanelVisibility,
 30→} from "./features/terminal/panel-visibility";
 31→import {
 32→  DEFAULT_TERMINAL_HEIGHT,
 33→  clampTerminalHeight,
 34→} from "./features/terminal/resize.ts";
 35→import { useLiveUpdates } from "./hooks/use-live-updates";
 36→import type { BranchInfo, CheckpointSummary, WorktreeInfo } from "./lib/ipc";
 37→import { SettingsView } from "./features/settings/SettingsView";
 38→import { DashboardView } from "./features/dashboard/DashboardView";
 39→import { ArrowLeft, GitCommit } from "lucide-react";
 40→
 41→export interface Tab {
 42→  id: string;
 43→  branch: string;
 44→  repoPath: string;
 45→  worktree: WorktreeInfo | null;
 46→  kind: "branch" | "agent";
 47→  agent: string | null;
 48→  hasActiveSession: boolean;
 49→}
 50→
 51→function resolveAgent(agent: string) {
 52→  return agent === "codex" ? "codex" : "claude-code";
 53→}
 54→
 55→export default function App() {
 56→  const [tabs, setTabs] = useState<Tab[]>([
 57→    {
 58→      id: "main",
 59→      branch: "main",
 60→      repoPath: "",
 61→      worktree: null,
 62→      kind: "branch",
 63→      agent: null,
 64→      hasActiveSession: false,
 65→    },
 66→  ]);
 67→  const [activeTabId, setActiveTabId] = useState("main");
 68→  const [sidebarWidth, setSidebarWidth] = useState(DEFAULT_SIDEBAR_WIDTH);
 69→  const [terminalHeight, setTerminalHeight] = useState(() => {
 70→    const storedHeight = Number(localStorage.getItem("entire:terminal-height"));
 71→    const initialHeight = Number.isFinite(storedHeight) && storedHeight > 0
 72→      ? storedHeight
 73→      : DEFAULT_TERMINAL_HEIGHT;
 74→
 75→    return clampTerminalHeight(initialHeight, window.innerHeight);
 76→  });
 77→  const [checkpointListWidth, setCheckpointListWidth] = useState(() => {
 78→    const stored = Number(localStorage.getItem("entire:checkpoint-list-width"));
 79→    return Number.isFinite(stored) && stored >= 200 ? Math.min(stored, 500) : 320;
 80→  });
 81→  const [terminalPanelVisibility, setTerminalPanelVisibility] = useState(
 82→    () => createTerminalPanelVisibility(["main"])
 83→  );
 84→  const [innerTab, setInnerTab] = useState<
 85→    "checkpoints" | "diff" | "insights" | "debug"
 86→  >("checkpoints");
 87→  const [selectedCheckpoint, setSelectedCheckpoint] =
 88→    useState<CheckpointSummary | null>(null);
 89→  const [checkpointInnerTab, setCheckpointInnerTab] = useState<
 90→    "transcript" | "diff" | "insights" | "debug"
 91→  >("transcript");
 92→
 93→  const [workspaceMap, setWorkspaceMap] = useState<Map<string, TerminalWorkspace>>(
 94→    () => new Map([["main", createTerminalWorkspace()]])
 95→  );
 96→  const [pendingAgentLaunch, setPendingAgentLaunch] = useState<{
 97→    tabId: string;
 98→    agent: string;
 99→    prompt: string;
100→  } | null>(null);
101→  const [isSidebarDialogOpen, setIsSidebarDialogOpen] = useState(false);
102→  const [isSettingsOpen, setIsSettingsOpen] = useState(false);
103→  const [activeView, setActiveView] = useState<"tabs" | "dashboard">("tabs");
104→
105→  const terminalRef = useRef<TerminalPanelHandle>(null);
106→
107→  // Load repos so we can auto-populate the initial tab
108→  const { data: repos } = useReposQuery();
109→
110→  // Auto-populate the initial tab's repoPath from the first discovered repo
111→  useEffect(() => {
112→    invoke("debug_log", {
113→      message: `useEffect[repos]: repos=${repos ? repos.length : "null"}, first repo path=${repos?.[0]?.path ?? "none"}`,
114→    }).catch(() => {});
115→
116→    if (!repos || repos.length === 0) return;
117→    setTabs((prev) => {
118→      const updated = prev.map((tab) => {
119→        if (tab.id === "main" && !tab.repoPath) {
120→          const repo = repos[0];
121→          const headBranch = repo.branches.find((b: { is_head: boolean }) => b.is_head);
122→          const newPath = repo.path;
123→          const newBranch = headBranch?.name ?? repo.branches[0]?.name ?? "main";
124→          invoke("debug_log", {
125→            message: `Auto-populating initial tab: repoPath=${newPath}, branch=${newBranch}`,
126→          }).catch(() => {});
127→          return {
128→            ...tab,
129→            repoPath: newPath,
130→            branch: newBranch,
131→          };
132→        }
133→        return tab;
134→      });
135→      return updated;
136→    });
137→  }, [repos]);
138→
139→  const activeTab = tabs.find((t) => t.id === activeTabId) ?? tabs[0];
140→  const activeWorkspace =
141→    workspaceMap.get(activeTabId) ?? createTerminalWorkspace();
142→  const isTerminalOpen = isTerminalPanelOpen(terminalPanelVisibility, activeTabId);
143→  const tabsWithSessions = tabs.map((tab) => ({
144→    ...tab,
145→    hasActiveSession: collectWorkspaceSurfaceIds(workspaceMap.get(tab.id)).length > 0,
146→  }));
147→
148→  // Live updates — watch active repo for checkpoint/session changes
149→  useLiveUpdates(activeTab.repoPath);
150→
151→  useEffect(() => {
152→    setWorkspaceMap((prev) => {
153→      let changed = false;
154→      const next = new Map(prev);
155→      for (const tab of tabs) {
156→        if (!next.has(tab.id)) {
157→          next.set(tab.id, createTerminalWorkspace());
158→          changed = true;
159→        }
160→      }
161→      return changed ? next : prev;
162→    });
163→  }, [tabs]);
164→
165→  useEffect(() => {
166→    setTerminalPanelVisibility((prev) =>
167→      syncTerminalPanelVisibility(
168→        prev,
169→        tabs.map((tab) => tab.id)
170→      )
171→    );
172→  }, [tabs]);
173→
174→  const handleWorkspaceChange = useCallback(
175→    (tabId: string, update: WorkspaceUpdate) => {
176→      setWorkspaceMap((prev) => {
177→        const next = new Map(prev);
178→        const current = next.get(tabId) ?? createTerminalWorkspace();
179→        next.set(
180→          tabId,
181→          typeof update === "function" ? update(current) : update
182→        );
183→        return next;
184→      });
185→    },
186→    []
187→  );
188→
189→  const handleSetTerminalOpen = useCallback((tabId: string, isOpen: boolean) => {
190→    setTerminalPanelVisibility((prev) => setTerminalPanelOpen(prev, tabId, isOpen));
191→  }, []);
192→
193→  // Terminal dispatch — open shell and optionally send a prompt
194→  const handleSendToAgent = useCallback(
195→    (agent: string, prompt: string) => {
196→      if (!activeTab.repoPath) return;
197→
198→      const resolvedAgent = resolveAgent(agent);
199→      const tabId = `agent:${resolvedAgent}:${Date.now()}`;
200→      const agentTab: Tab = {
201→        id: tabId,
202→        branch: activeTab.branch,
203→        repoPath: activeTab.repoPath,
204→        worktree: activeTab.worktree,
205→        kind: "agent",
206→        agent: resolvedAgent,
207→        hasActiveSession: false,
208→      };
209→
210→      setTabs((prev) => [...prev, agentTab]);
211→      setActiveTabId(tabId);
212→      handleSetTerminalOpen(tabId, true);
213→      setPendingAgentLaunch({ tabId, agent: resolvedAgent, prompt });
214→    },
215→    [activeTab, handleSetTerminalOpen]
216→  );
217→
218→  useEffect(() => {
219→    if (!pendingAgentLaunch) return;
220→    if (pendingAgentLaunch.tabId !== activeTabId) return;
221→    if (!isTerminalOpen) return;
222→
223→    let cancelled = false;
224→    let timer = 0;
225→
226→    const launch = () => {
227→      if (cancelled) return;
228→      if (!terminalRef.current) {
229→        timer = window.setTimeout(launch, 50);
230→        return;
231→      }
232→
233→      terminalRef.current
234→        .launchSession({
235→          agent: pendingAgentLaunch.agent,
236→          prompt: pendingAgentLaunch.prompt,
237→        })
238→        .finally(() => {
239→          setPendingAgentLaunch((current) =>
240→            current?.tabId === pendingAgentLaunch.tabId ? null : current
241→          );
242→        });
243→    };
244→
245→    timer = window.setTimeout(launch, 50);
246→    return () => {
247→      cancelled = true;
248→      window.clearTimeout(timer);
249→    };
250→  }, [activeTabId, isTerminalOpen, pendingAgentLaunch]);
251→
252→  // Persist UI state to localStorage
253→  useEffect(() => {
254→    localStorage.setItem("entire:terminal-height", String(terminalHeight));
255→  }, [terminalHeight]);
256→  useEffect(() => {
257→    localStorage.setItem("entire:checkpoint-list-width", String(checkpointListWidth));
258→  }, [checkpointListWidth]);
259→  useEffect(() => {
260→    function handleWindowResize() {
261→      setTerminalHeight((currentHeight) =>
262→        clampTerminalHeight(currentHeight, window.innerHeight)
263→      );
264→    }
265→
266→    window.addEventListener("resize", handleWindowResize);
267→    return () => window.removeEventListener("resize", handleWindowResize);
268→  }, []);
269→
270→  // Clear selected checkpoint when switching branch tabs
271→  useEffect(() => {
272→    setSelectedCheckpoint(null);
273→    setCheckpointInnerTab("transcript");
274→  }, [activeTabId]);
275→
276→  // Keyboard shortcuts
277→  useEffect(() => {
278→    function onKeyDown(e: KeyboardEvent) {
279→      const meta = e.metaKey || e.ctrlKey;
280→
281→      // Cmd+K = focus search
282→      if (meta && e.key === "k") {
283→        e.preventDefault();
284→        document.querySelector<HTMLInputElement>('input[placeholder*="Search"]')?.focus();
285→      }
286→      // Ctrl+` = toggle terminal
287→      if (e.ctrlKey && e.key === "`") {
288→        e.preventDefault();
289→        handleSetTerminalOpen(activeTabId, !isTerminalOpen);
290→      }
291→      // Cmd+W = close active tab
292→      if (meta && e.key === "w") {
293→        e.preventDefault();
294→        handleCloseTab(activeTabId);
295→      }
296→      // Cmd+1-9 = switch to tab by index
297→      if (meta && e.key >= "1" && e.key <= "9") {
298→        e.preventDefault();
299→        const idx = parseInt(e.key) - 1;
300→        if (idx < tabs.length) {
301→          setActiveTabId(tabs[idx].id);
302→        }
303→      }
304→      // Cmd+[ / Cmd+] = prev/next tab
305→      if (meta && e.key === "[") {
306→        e.preventDefault();
307→        const idx = tabs.findIndex((t) => t.id === activeTabId);
308→        if (idx > 0) setActiveTabId(tabs[idx - 1].id);
309→      }
310→      if (meta && e.key === "]") {
311→        e.preventDefault();
312→        const idx = tabs.findIndex((t) => t.id === activeTabId);
313→        if (idx < tabs.length - 1) setActiveTabId(tabs[idx + 1].id);
314→      }
315→      // Escape = deselect checkpoint
316→      if (e.key === "Escape" && selectedCheckpoint) {
317→        setSelectedCheckpoint(null);
318→      }
319→    }
320→    window.addEventListener("keydown", onKeyDown);
321→    return () => window.removeEventListener("keydown", onKeyDown);
322→  }, [activeTabId, handleSetTerminalOpen, isTerminalOpen, tabs, selectedCheckpoint]);
323→
324→  function handleBranchSelect(branch: BranchInfo, repoPath: string) {
325→    const newTab = createBranchTab(branch, repoPath);
326→    const existing = tabs.find(
327→      (t) =>
328→        t.kind === "branch" &&
329→        t.branch === newTab.branch &&
330→        t.repoPath === newTab.repoPath
331→    );
332→    if (existing) {
333→      setActiveTabId(existing.id);
334→    } else {
335→      setTabs([...tabs, newTab]);
336→      setActiveTabId(newTab.id);
337→    }
338→  }
339→
340→  function handleWorktreeSelect(wt: WorktreeInfo) {
341→    const newTab = createWorktreeTab(wt);
342→    const existing = tabs.find(
343→      (t) =>
344→        t.kind === "branch" &&
345→        t.branch === newTab.branch &&
346→        t.repoPath === newTab.repoPath
347→    );
348→    if (existing) {
349→      setActiveTabId(existing.id);
350→    } else {
351→      setTabs([...tabs, newTab]);
352→      setActiveTabId(newTab.id);
353→    }
354→  }
355→
356→  function handleCloseTab(tabId: string) {
357→    if (tabs.length <= 1) return;
358→    const idx = tabs.findIndex((t) => t.id === tabId);
359→    const newTabs = tabs.filter((t) => t.id !== tabId);
360→    setTabs(newTabs);
361→    if (activeTabId === tabId) {
362→      setActiveTabId(newTabs[Math.max(0, idx - 1)].id);
363→    }
364→    const closedWorkspace = workspaceMap.get(tabId);
365→    for (const surfaceId of collectWorkspaceSurfaceIds(closedWorkspace)) {
366→      invoke("ghostty_destroy_surface", { surfaceId }).catch(console.error);
367→    }
368→    setWorkspaceMap((prev) => {
369→      const next = new Map(prev);
370→      next.delete(tabId);
371→      return next;
372→    });
373→  }
374→
375→  function handleBranchDeleted(branchName: string, repoPath: string) {
376→    const tabsToRemove = tabs.filter(
377→      (tab) =>
378→        tab.kind === "branch" &&
379→        tab.worktree === null &&
380→        tab.branch === branchName &&
381→        tab.repoPath === repoPath
382→    );
383→
384→    if (tabsToRemove.length === 0) {
385→      return;
386→    }
387→
388→    const nextTabs = tabs.filter((tab) => !tabsToRemove.some((candidate) => candidate.id === tab.id));
389→    setTabs(nextTabs);
390→
391→    if (tabsToRemove.some((tab) => tab.id === activeTabId) && nextTabs.length > 0) {
392→      setActiveTabId(nextTabs[0].id);
393→    }
394→
395→    setWorkspaceMap((prev) => {
396→      const next = new Map(prev);
397→      for (const tab of tabsToRemove) {
398→        const closedWorkspace = next.get(tab.id);
399→        for (const surfaceId of collectWorkspaceSurfaceIds(closedWorkspace)) {
400→          invoke("ghostty_destroy_surface", { surfaceId }).catch(console.error);
401→        }
402→        next.delete(tab.id);
403→      }
404→      return next;
405→    });
406→  }
407→
408→  function handleWorktreeDeleted(worktreePath: string) {
409→    const cleanup = planWorktreeDeletionCleanup({
410→      tabs,
411→      activeTabId,
412→      worktreePath,
413→    });
414→
415→    if (cleanup.removedTabIds.length === 0) {
416→      return;
417→    }
418→
419→    setTabs(cleanup.remainingTabs);
420→
421→    if (cleanup.nextActiveTabId && cleanup.nextActiveTabId !== activeTabId) {
422→      setActiveTabId(cleanup.nextActiveTabId);
423→    }
424→
425→    setWorkspaceMap((prev) => {
426→      const next = new Map(prev);
427→      for (const tabId of cleanup.removedTabIds) {
428→        const closedWorkspace = next.get(tabId);
429→        for (const surfaceId of collectWorkspaceSurfaceIds(closedWorkspace)) {
430→          invoke("ghostty_destroy_surface", { surfaceId }).catch(console.error);
431→        }
432→        next.delete(tabId);
433→      }
434→      return next;
435→    });
436→  }
437→
438→  function handleResizeStart(e: React.MouseEvent) {
439→    e.preventDefault();
440→    const startY = e.clientY;
441→    const startHeight = terminalHeight;
442→
443→    function onMouseMove(ev: MouseEvent) {
444→      const delta = startY - ev.clientY;
445→      setTerminalHeight(
446→        clampTerminalHeight(startHeight + delta, window.innerHeight)
447→      );
448→    }
449→    function onMouseUp() {
450→      window.removeEventListener("mousemove", onMouseMove);
451→      window.removeEventListener("mouseup", onMouseUp);
452→    }
453→    window.addEventListener("mousemove", onMouseMove);
454→    window.addEventListener("mouseup", onMouseUp);
455→  }
456→
457→  function handleSidebarResizeStart(e: React.MouseEvent<HTMLDivElement>) {
458→    e.preventDefault();
459→    const startX = e.clientX;
460→    const startWidth = sidebarWidth;
461→
462→    function onMouseMove(ev: MouseEvent) {
463→      const delta = ev.clientX - startX;
464→      setSidebarWidth(clampSidebarWidth(startWidth + delta));
465→    }
466→
467→    function onMouseUp() {
468→      window.removeEventListener("mousemove", onMouseMove);
469→      window.removeEventListener("mouseup", onMouseUp);
470→    }
471→
472→    window.addEventListener("mousemove", onMouseMove);
473→    window.addEventListener("mouseup", onMouseUp);
474→  }
475→
476→  function handleCheckpointListResizeStart(e: React.MouseEvent<HTMLDivElement>) {
477→    e.preventDefault();
478→    const startX = e.clientX;
479→    const startWidth = checkpointListWidth;
480→
481→    function onMouseMove(ev: MouseEvent) {
482→      const delta = ev.clientX - startX;
483→      setCheckpointListWidth(Math.max(200, Math.min(500, startWidth + delta)));
484→    }
485→
486→    function onMouseUp() {
487→      window.removeEventListener("mousemove", onMouseMove);
488→      window.removeEventListener("mouseup", onMouseUp);
489→    }
490→
491→    window.addEventListener("mousemove", onMouseMove);
492→    window.addEventListener("mouseup", onMouseUp);
493→  }
494→
495→  const repoName = activeTab.repoPath
496→    ? activeTab.repoPath.split("/").pop()
497→    : "";
498→
499→  return (
500→    <div className="flex h-screen flex-col">
501→      <TitleBar
502→        title={`Entire — ${repoName ? `${repoName}/` : ""}${activeTab?.branch ?? ""}`}
503→        isDashboard={activeView === "dashboard"}
504→        onToggleDashboard={() => setActiveView((v) => (v === "tabs" ? "dashboard" : "tabs"))}
505→      />
506→
507→      <div className="flex flex-1 overflow-hidden">
508→        {/* Sidebar */}
509→        <Sidebar
510→          activeTab={activeTab}
511→          width={sidebarWidth}
512→          onBranchSelect={handleBranchSelect}
513→          onBranchDeleted={handleBranchDeleted}
514→          onWorktreeDeleted={handleWorktreeDeleted}
515→          onWorktreeSelect={handleWorktreeSelect}
516→          onResizeStart={handleSidebarResizeStart}
517→          onDialogOpen={setIsSidebarDialogOpen}
518→          onOpenSettings={() => setIsSettingsOpen(true)}
519→        />
520→
521→        {/* Main content */}
522→        <div className="flex flex-1 flex-col overflow-hidden">
523→          <TabBar
524→            tabs={tabsWithSessions}
525→            activeTabId={activeTabId}
526→            onSelectTab={setActiveTabId}
527→            onCloseTab={handleCloseTab}
528→          />
529→
530→          {activeView === "dashboard" ? (
531→            <DashboardView repoPath={activeTab.repoPath} />
532→          ) : (
533→          <div className="flex flex-1 flex-col overflow-hidden">
534→            {/* Inner tabs */}
535→            <div className="flex gap-0 border-b border-border-subtle bg-bg px-5 pt-3">
536→              {(["checkpoints", "diff", "insights", "debug"] as const).map((tab) => (
537→                <button
538→                  key={tab}
539→                  onClick={() => setInnerTab(tab)}
540→                  className={`border-b-2 px-4 pb-2 text-xs font-medium capitalize transition-colors ${
541→                    innerTab === tab
542→                      ? "border-accent text-fg"
543→                      : "border-transparent text-fg-subtle hover:text-fg-muted"
544→                  }`}
545→                >
546→                  {tab === "checkpoints"
547→                    ? "Checkpoints"
548→                    : tab === "diff"
549→                      ? "Diff"
550→                      : tab === "insights"
551→                        ? "Insights"
552→                        : "Debug"}
553→                </button>
554→              ))}
555→            </div>
556→
557→            {/* Main view */}
558→            <div className="flex flex-1 overflow-hidden bg-bg">
559→              {innerTab === "checkpoints" && (
560→                <>
561→                  {/* Checkpoint list — always visible when on checkpoints tab */}
562→                  <div
563→                    className={`overflow-y-auto ${
564→                      selectedCheckpoint
565→                        ? "shrink-0 border-r border-border-subtle"
566→                        : "flex-1"
567→                    }`}
568→                    style={selectedCheckpoint ? { width: checkpointListWidth } : undefined}
569→                  >
570→                    <CheckpointList
571→                      repoPath={activeTab.repoPath}
572→                      branch={activeTab.branch}
573→                      onSelectCheckpoint={(cp) => {
574→                        setSelectedCheckpoint(cp);
575→                        setCheckpointInnerTab("transcript");
576→                      }}
577→                    />
578→                  </div>
579→
580→                  {/* Checkpoint list resize handle */}
581→                  {selectedCheckpoint && (
582→                    <div
583→                      onMouseDown={handleCheckpointListResizeStart}
584→                      className="w-[3px] shrink-0 cursor-col-resize bg-border transition-colors hover:bg-accent"
585→                    />
586→                  )}
587→
588→                  {/* Checkpoint detail panel */}
589→                  {selectedCheckpoint && (
590→                    <div className="flex flex-1 flex-col overflow-hidden">
591→                      {/* Detail header */}
592→                      <div className="flex items-center gap-3 border-b border-border-subtle px-4 py-2.5">
593→                        <button
594→                          onClick={() => setSelectedCheckpoint(null)}
595→                          className="flex items-center gap-1.5 text-xs text-fg-subtle transition-colors hover:text-fg"
596→                        >
597→                          <ArrowLeft size={14} />
598→                        </button>
599→                        <GitCommit size={14} className="text-fg-subtle" />
600→                        <span className="font-mono text-xs text-accent-fg">
601→                          {selectedCheckpoint.commit_sha
602→                            ? selectedCheckpoint.commit_sha.slice(0, 7)
603→                            : selectedCheckpoint.checkpoint_id.slice(0, 7)}
604→                        </span>
605→                        <span className="truncate text-xs text-fg-muted">
606→                          {selectedCheckpoint.commit_message || "Untitled"}
607→                        </span>
608→                      </div>
609→
610→                      {/* Checkpoint sub-tabs */}
611→                      <div className="flex gap-0 border-b border-border-subtle bg-bg px-4 pt-2">
612→                        {(["transcript", "diff", "insights", "debug"] as const).map(
613→                          (tab) => (
614→                            <button
615→                              key={tab}
616→                              onClick={() => setCheckpointInnerTab(tab)}
617→                              className={`border-b-2 px-3 pb-1.5 text-[11px] font-medium capitalize transition-colors ${
618→                                checkpointInnerTab === tab
619→                                  ? "border-accent text-fg"
620→                                  : "border-transparent text-fg-subtle hover:text-fg-muted"
621→                              }`}
622→                            >
623→                              {tab === "transcript"
