import { useState, useRef, useCallback } from "react";
import { useJournalEntriesQuery, useJournalDatesQuery } from "../../hooks/use-tauri-query";
import { JournalFeed } from "./JournalFeed";
import { DateJumper } from "./DateJumper";
import { GenerateDialog } from "./GenerateDialog";
import type { RepoInfo } from "../../lib/ipc";

interface DashboardViewProps {
  repos: RepoInfo[];
}

export function DashboardView({ repos }: DashboardViewProps) {
  const [selectedRepoPath, setSelectedRepoPath] = useState<string>("");
  const [showGenerateDialog, setShowGenerateDialog] = useState(false);
  const feedRef = useRef<HTMLDivElement>(null);

  // Use first repo as default when selectedRepoPath is empty or invalid
  const repoPath =
    repos.find((r) => r.path === selectedRepoPath)?.path ?? repos[0]?.path ?? "";

  const { data: entries = [], refetch: refetchEntries } = useJournalEntriesQuery(repoPath);
  const { data: dates = [] } = useJournalDatesQuery(repoPath);

  const today = new Date().toISOString().slice(0, 10);

  const handleDateClick = useCallback((date: string) => {
    const el = document.getElementById(`journal-${date}`);
    if (el) {
      el.scrollIntoView({ behavior: "smooth", block: "start" });
    }
  }, []);

  return (
    <div className="flex flex-1 flex-col overflow-hidden">
      {/* Dashboard toolbar */}
      <div className="flex items-center justify-between border-b border-border bg-bg px-5 py-3">
        <div className="flex items-center gap-3">
          <h1 className="text-sm font-semibold text-fg">Work Journal</h1>
          {repos.length > 1 && (
            <select
              value={repoPath}
              onChange={(e) => setSelectedRepoPath(e.target.value)}
              className="rounded-md border border-border bg-bg-raised px-2 py-1 text-xs text-fg"
            >
              {repos.map((repo) => (
                <option key={repo.path} value={repo.path}>
                  {repo.name}
                </option>
              ))}
            </select>
          )}
          {repos.length === 1 && (
            <span className="text-xs text-fg-subtle">{repos[0].name}</span>
          )}
        </div>
        <button
          onClick={() => setShowGenerateDialog(true)}
          disabled={!repoPath}
          className="rounded-md bg-accent px-3 py-1.5 text-xs font-semibold text-white hover:bg-accent/90 disabled:opacity-50"
        >
          ✨ Generate Today's Summary
        </button>
      </div>

      {/* Feed + Date Jumper */}
      {repoPath ? (
        <div className="flex flex-1 overflow-hidden">
          <div ref={feedRef} className="flex-1 overflow-y-auto px-8 py-6">
            <div className="mx-auto max-w-[720px]">
              <JournalFeed entries={entries} />
            </div>
          </div>

          <DateJumper dates={dates} onDateClick={handleDateClick} />
        </div>
      ) : (
        <div className="flex flex-1 items-center justify-center text-sm text-fg-subtle">
          No repos registered. Use the sidebar "Add Repo" button to register a repo.
        </div>
      )}

      {/* Generate dialog */}
      {showGenerateDialog && repoPath && (
        <GenerateDialog
          repoPath={repoPath}
          date={today}
          onClose={() => setShowGenerateDialog(false)}
          onGenerated={() => refetchEntries()}
        />
      )}
    </div>
  );
}

