 51→
 52→/// Get the journal directory for a repo, creating it if needed.
 53→pub fn journal_dir(repo_path: &str) -> PathBuf {
 54→    let dir = Path::new(repo_path).join(".entire/journal");
 55→    let _ = fs::create_dir_all(&dir);
 56→    dir
 57→}
 58→
 59→/// List journal entries from markdown files, sorted newest first.
 60→/// `limit` defaults to 100.
 61→pub fn list_entries(repo_path: &str, limit: usize) -> Result<Vec<JournalEntry>, String> {
 62→    let dir = journal_dir(repo_path);
 63→    if !dir.exists() {
 64→        return Ok(Vec::new());
 65→    }
 66→
 67→    let mut files: Vec<_> = fs::read_dir(&dir)
 68→        .map_err(|e| format!("Failed to read journal dir: {}", e))?
 69→        .filter_map(|e| e.ok())
 70→        .filter(|e| {
 71→            e.path()
 72→                .extension()
 73→                .map_or(false, |ext| ext == "md")
 74→        })
 75→        .collect();
 76→
 77→    // Sort by filename descending (YYYY-MM-DD.md sorts chronologically)
 78→    files.sort_by(|a, b| b.file_name().cmp(&a.file_name()));
 79→    files.truncate(limit);
 80→
 81→    let mut entries = Vec::new();
 82→    for file in files {
 83→        let content = fs::read_to_string(file.path())
 84→            .map_err(|e| format!("Failed to read {}: {}", file.path().display(), e))?;
 85→        match parse_markdown(&content) {
 86→            Ok(entry) => entries.push(entry),
 87→            Err(e) => eprintln!("Skipping {}: {}", file.path().display(), e),
 88→        }
 89→    }
 90→
 91→    Ok(entries)
 92→}
 93→
 94→/// Get a single journal entry by date (YYYY-MM-DD).
 95→pub fn get_entry(repo_path: &str, date: &str) -> Result<JournalEntry, String> {
 96→    let path = journal_dir(repo_path).join(format!("{}.md", date));
 97→    if !path.exists() {
 98→        return Err(format!("No journal entry for {}", date));
 99→    }
100→    let content = fs::read_to_string(&path)
101→        .map_err(|e| format!("Failed to read entry: {}", e))?;
102→    parse_markdown(&content)
103→}
104→
105→/// Get date info for the date jumper rail.
106→pub fn list_dates(repo_path: &str, limit: usize) -> Result<Vec<JournalDateInfo>, String> {
107→    let dir = journal_dir(repo_path);
108→
109→    // Build a set of dates that have entries
110→    let mut entry_dates = std::collections::HashSet::new();
111→    let mut stats_map = std::collections::HashMap::new();
112→
113→    if dir.exists() {
114→        if let Ok(read_dir) = fs::read_dir(&dir) {
115→            for entry in read_dir.filter_map(|e| e.ok()) {
116→                let path = entry.path();
117→                if path.extension().map_or(false, |ext| ext == "md") {
118→                    if let Some(stem) = path.file_stem().and_then(|s| s.to_str()) {
119→                        entry_dates.insert(stem.to_string());
120→                        // Quick parse frontmatter for stats
121→                        if let Ok(content) = fs::read_to_string(&path) {
122→                            if let Ok(parsed) = parse_frontmatter_only(&content) {
123→                                stats_map.insert(stem.to_string(), parsed);
124→                            }
125→                        }
126→                    }
127→                }
128→            }
129→        }
130→    }
131→
132→    // Generate last `limit` days
133→    let today = current_date();
134→    let mut dates = Vec::new();
135→    for i in 0..limit {
136→        let date = subtract_days(&today, i as i64);
137→        let has_entry = entry_dates.contains(&date);
138→        let activity_level = stats_map
139→            .get(&date)
140→            .map(|s| {
141→                // Scale lines_changed to 0-4
142→                match s.lines_changed {
143→                    0 => 0,
144→                    1..=100 => 1,
145→                    101..=500 => 2,
146→                    501..=1000 => 3,
147→                    _ => 4,
148→                }
149→            })
150→            .unwrap_or(0);
151→
152→        dates.push(JournalDateInfo {
153→            date,
154→            has_entry,
155→            activity_level,
156→        });
157→    }
158→
159→    Ok(dates)
160→}
161→
162→/// Save a journal entry as a markdown file.
163→pub fn save_entry(repo_path: &str, entry: &JournalEntry) -> Result<(), String> {
164→    let dir = journal_dir(repo_path);
165→    let path = dir.join(format!("{}.md", entry.date));
166→    let content = render_markdown(entry);
167→    fs::write(&path, content)
168→        .map_err(|e| format!("Failed to write journal entry: {}", e))
169→}
170→
171→/// Parse a journal markdown file into a JournalEntry.
172→pub fn parse_markdown(content: &str) -> Result<JournalEntry, String> {
173→    // Split frontmatter from body
174→    let (frontmatter, body) = split_frontmatter(content)?;
175→
176→    // Parse YAML frontmatter
177→    let date = extract_yaml_field(&frontmatter, "date")
178→        .ok_or("Missing date in frontmatter")?;
179→    let generated_at = extract_yaml_field(&frontmatter, "generated_at")
180→        .unwrap_or_default();
181→    let stats = parse_frontmatter_only(content)?;
182→
183→    // Parse body into repo sections and other work
184→    let (repos, other_work) = parse_body(&body);
185→
186→    Ok(JournalEntry {
187→        date,
188→        generated_at,
189→        repos,
190→        other_work,
191→        stats,
192→    })
193→}
194→
195→fn split_frontmatter(content: &str) -> Result<(String, String), String> {
196→    let content = content.trim();
197→    if !content.starts_with("---") {
198→        return Err("No frontmatter found".to_string());
199→    }
200→    let rest = &content[3..];
201→    let end = rest.find("---").ok_or("Unterminated frontmatter")?;
202→    let frontmatter = rest[..end].trim().to_string();
203→    let body = rest[end + 3..].trim().to_string();
204→    Ok((frontmatter, body))
205→}
206→
207→fn extract_yaml_field(yaml: &str, field: &str) -> Option<String> {
208→    for line in yaml.lines() {
209→        let line = line.trim();
210→        if let Some(rest) = line.strip_prefix(&format!("{}:", field)) {
211→            let value = rest.trim().trim_matches('"').trim_matches('\'');
212→            if !value.is_empty() {
213→                return Some(value.to_string());
214→            }
215→        }
216→    }
217→    None
218→}
219→
220→fn parse_frontmatter_only(content: &str) -> Result<JournalStats, String> {
221→    let (frontmatter, _) = split_frontmatter(content)?;
222→
223→    let lines_changed = extract_yaml_field(&frontmatter, "lines_changed")
224→        .and_then(|v| v.parse().ok())
225→        .unwrap_or(0);
226→    let sessions = extract_yaml_field(&frontmatter, "sessions")
227→        .and_then(|v| v.parse().ok())
228→        .unwrap_or(0);
229→    let prs = extract_yaml_field(&frontmatter, "prs")
230→        .and_then(|v| v.parse().ok())
231→        .unwrap_or(0);
232→    let ai_authored_pct = extract_yaml_field(&frontmatter, "ai_authored_pct")
233→        .and_then(|v| v.parse().ok())
234→        .unwrap_or(0);
235→    let tokens = extract_yaml_field(&frontmatter, "tokens")
236→        .and_then(|v| v.parse().ok())
237→        .unwrap_or(0);
238→
239→    Ok(JournalStats {
240→        lines_changed,
241→        sessions,
242→        prs,
243→        ai_authored_pct,
244→        tokens,
245→    })
246→}
247→
248→fn parse_body(body: &str) -> (Vec<RepoSection>, Vec<String>) {
249→    let mut repos = Vec::new();
250→    let mut other_work = Vec::new();
251→    let mut current_repo: Option<RepoSection> = None;
252→    let mut in_prs = false;
253→    let mut in_other_work = false;
254→
255→    for line in body.lines() {
256→        let trimmed = line.trim();
257→
258→        // H2 heading = repo name or "Other Work"
259→        if let Some(heading) = trimmed.strip_prefix("## ") {
260→            // Save previous repo
261→            if let Some(repo) = current_repo.take() {
262→                repos.push(repo);
263→            }
264→            in_prs = false;
265→
266→            if heading == "Other Work" {
267→                in_other_work = true;
268→                continue;
269→            }
270→
271→            in_other_work = false;
272→            current_repo = Some(RepoSection {
273→                name: heading.to_string(),
274→                lines_added: 0,
275→                lines_removed: 0,
276→                accomplishments: Vec::new(),
277→                pull_requests: Vec::new(),
278→            });
279→            continue;
280→        }
281→
282→        // H3 heading = "Pull Requests" subsection
283→        if trimmed.starts_with("### Pull Requests") {
284→            in_prs = true;
285→            continue;
286→        }
287→
288→        // Lines diff stats: _+716 -131_
289→        if trimmed.starts_with("_+") && trimmed.ends_with('_') {
290→            if let Some(ref mut repo) = current_repo {
291→                let inner = &trimmed[1..trimmed.len() - 1];
292→                let parts: Vec<&str> = inner.split_whitespace().collect();
293→                if parts.len() == 2 {
294→                    repo.lines_added = parts[0].trim_start_matches('+').parse().unwrap_or(0);
295→                    repo.lines_removed = parts[1].trim_start_matches('-').parse().unwrap_or(0);
296→                }
297→            }
298→            continue;
299→        }
300→
301→        // Bullet points
302→        if let Some(bullet_content) = trimmed.strip_prefix("- ") {
303→            if in_other_work {
304→                other_work.push(bullet_content.to_string());
305→            } else if in_prs {
306→                if let Some(ref mut repo) = current_repo {
307→                    if let Some(pr) = parse_pr_line(bullet_content) {
308→                        repo.pull_requests.push(pr);
309→                    }
310→                }
311→            } else if let Some(ref mut repo) = current_repo {
312→                repo.accomplishments.push(bullet_content.to_string());
313→            }
314→        }
315→    }
316→
317→    // Don't forget last repo
318→    if let Some(repo) = current_repo {
319→        repos.push(repo);
320→    }
321→
322→    (repos, other_work)
323→}
324→
325→/// Parse a PR line like: **Settings page rebuild** #142 — merged
326→fn parse_pr_line(line: &str) -> Option<JournalPR> {
327→    // Pattern: **title** #number — status
328→    let bold_start = line.find("**")?;
329→    let bold_end = line[bold_start + 2..].find("**")? + bold_start + 2;
330→    let title = line[bold_start + 2..bold_end].to_string();
331→
332→    let rest = &line[bold_end + 2..];
333→    let hash_pos = rest.find('#')?;
334→    let after_hash = &rest[hash_pos + 1..];
335→
336→    // Find the number (digits until non-digit)
