pub mod generate;
pub mod github;

use serde::{Deserialize, Serialize};
use std::fs;
use std::path::{Path, PathBuf};

#[derive(Debug, Serialize, Deserialize, Clone)]
pub struct JournalEntry {
    pub date: String,
    pub generated_at: String,
    pub repos: Vec<RepoSection>,
    pub other_work: Vec<String>,
    pub stats: JournalStats,
}

#[derive(Debug, Serialize, Deserialize, Clone)]
pub struct RepoSection {
    pub name: String,
    pub lines_added: u64,
    pub lines_removed: u64,
    pub accomplishments: Vec<String>,
    pub pull_requests: Vec<JournalPR>,
}

#[derive(Debug, Serialize, Deserialize, Clone)]
pub struct JournalPR {
    pub title: String,
    pub number: u64,
    pub status: String, // "open", "merged", "closed"
    pub additions: u64,
    pub deletions: u64,
    pub url: String,
}

#[derive(Debug, Serialize, Deserialize, Clone)]
pub struct JournalStats {
    pub lines_changed: u64,
    pub sessions: u64,
    pub prs: u64,
    pub ai_authored_pct: u64,
    pub tokens: u64,
}

#[derive(Debug, Serialize, Clone)]
pub struct JournalDateInfo {
    pub date: String,
    pub has_entry: bool,
    pub activity_level: u32, // 0-4
}

/// Get the journal directory for a repo, creating it if needed.
pub fn journal_dir(repo_path: &str) -> PathBuf {
    let dir = Path::new(repo_path).join(".entire/journal");
    let _ = fs::create_dir_all(&dir);
    dir
}

/// List journal entries from markdown files, sorted newest first.
/// `limit` defaults to 100.
pub fn list_entries(repo_path: &str, limit: usize) -> Result<Vec<JournalEntry>, String> {
    let dir = journal_dir(repo_path);
    if !dir.exists() {
        return Ok(Vec::new());
    }

    let mut files: Vec<_> = fs::read_dir(&dir)
        .map_err(|e| format!("Failed to read journal dir: {}", e))?
        .filter_map(|e| e.ok())
        .filter(|e| {
            e.path()
                .extension()
                .map_or(false, |ext| ext == "md")
        })
        .collect();

    // Sort by filename descending (YYYY-MM-DD.md sorts chronologically)
    files.sort_by(|a, b| b.file_name().cmp(&a.file_name()));
    files.truncate(limit);

    let mut entries = Vec::new();
    for file in files {
        let content = fs::read_to_string(file.path())
            .map_err(|e| format!("Failed to read {}: {}", file.path().display(), e))?;
        match parse_markdown(&content) {
            Ok(entry) => entries.push(entry),
            Err(e) => eprintln!("Skipping {}: {}", file.path().display(), e),
        }
    }

    Ok(entries)
}

/// Get a single journal entry by date (YYYY-MM-DD).
pub fn get_entry(repo_path: &str, date: &str) -> Result<JournalEntry, String> {
    let path = journal_dir(repo_path).join(format!("{}.md", date));
    if !path.exists() {
        return Err(format!("No journal entry for {}", date));
    }
    let content = fs::read_to_string(&path)
        .map_err(|e| format!("Failed to read entry: {}", e))?;
    parse_markdown(&content)
}

/// Get date info for the date jumper rail.
pub fn list_dates(repo_path: &str, limit: usize) -> Result<Vec<JournalDateInfo>, String> {
    let dir = journal_dir(repo_path);

    // Build a set of dates that have entries
    let mut entry_dates = std::collections::HashSet::new();
    let mut stats_map = std::collections::HashMap::new();

    if dir.exists() {
        if let Ok(read_dir) = fs::read_dir(&dir) {
            for entry in read_dir.filter_map(|e| e.ok()) {
                let path = entry.path();
                if path.extension().map_or(false, |ext| ext == "md") {
                    if let Some(stem) = path.file_stem().and_then(|s| s.to_str()) {
                        entry_dates.insert(stem.to_string());
                        // Quick parse frontmatter for stats
                        if let Ok(content) = fs::read_to_string(&path) {
                            if let Ok(parsed) = parse_frontmatter_only(&content) {
                                stats_map.insert(stem.to_string(), parsed);
                            }
                        }
                    }
                }
            }
        }
    }

    // Generate last `limit` days
    let today = current_date();
    let mut dates = Vec::new();
    for i in 0..limit {
        let date = subtract_days(&today, i as i64);
        let has_entry = entry_dates.contains(&date);
        let activity_level = stats_map
            .get(&date)
            .map(|s| {
                // Scale lines_changed to 0-4
                match s.lines_changed {
                    0 => 0,
                    1..=100 => 1,
                    101..=500 => 2,
                    501..=1000 => 3,
                    _ => 4,
                }
            })
            .unwrap_or(0);

        dates.push(JournalDateInfo {
            date,
            has_entry,
            activity_level,
        });
    }

    Ok(dates)
}

/// Save a journal entry as a markdown file.
pub fn save_entry(repo_path: &str, entry: &JournalEntry) -> Result<(), String> {
    let dir = journal_dir(repo_path);
    let path = dir.join(format!("{}.md", entry.date));
    let content = render_markdown(entry);
    fs::write(&path, content)
        .map_err(|e| format!("Failed to write journal entry: {}", e))
}

/// Parse a journal markdown file into a JournalEntry.
pub fn parse_markdown(content: &str) -> Result<JournalEntry, String> {
    // Split frontmatter from body
    let (frontmatter, body) = split_frontmatter(content)?;

    // Parse YAML frontmatter
    let date = extract_yaml_field(&frontmatter, "date")
        .ok_or("Missing date in frontmatter")?;
    let generated_at = extract_yaml_field(&frontmatter, "generated_at")
        .unwrap_or_default();
    let stats = parse_frontmatter_only(content)?;

    // Parse body into repo sections and other work
    let (repos, other_work) = parse_body(&body);

    Ok(JournalEntry {
        date,
        generated_at,
        repos,
        other_work,
        stats,
    })
}

fn split_frontmatter(content: &str) -> Result<(String, String), String> {
    let content = content.trim();
    if !content.starts_with("---") {
        return Err("No frontmatter found".to_string());
    }
    let rest = &content[3..];
    let end = rest.find("---").ok_or("Unterminated frontmatter")?;
    let frontmatter = rest[..end].trim().to_string();
    let body = rest[end + 3..].trim().to_string();
    Ok((frontmatter, body))
}

fn extract_yaml_field(yaml: &str, field: &str) -> Option<String> {
    for line in yaml.lines() {
        let line = line.trim();
        if let Some(rest) = line.strip_prefix(&format!("{}:", field)) {
            let value = rest.trim().trim_matches('"').trim_matches('\'');
            if !value.is_empty() {
                return Some(value.to_string());
            }
        }
    }
    None
}

fn parse_frontmatter_only(content: &str) -> Result<JournalStats, String> {
    let (frontmatter, _) = split_frontmatter(content)?;

    let lines_changed = extract_yaml_field(&frontmatter, "lines_changed")
        .and_then(|v| v.parse().ok())
        .unwrap_or(0);
    let sessions = extract_yaml_field(&frontmatter, "sessions")
        .and_then(|v| v.parse().ok())
        .unwrap_or(0);
    let prs = extract_yaml_field(&frontmatter, "prs")
        .and_then(|v| v.parse().ok())
        .unwrap_or(0);
    let ai_authored_pct = extract_yaml_field(&frontmatter, "ai_authored_pct")
        .and_then(|v| v.parse().ok())
        .unwrap_or(0);
    let tokens = extract_yaml_field(&frontmatter, "tokens")
        .and_then(|v| v.parse().ok())
        .unwrap_or(0);

    Ok(JournalStats {
        lines_changed,
        sessions,
        prs,
        ai_authored_pct,
        tokens,
    })
}

fn parse_body(body: &str) -> (Vec<RepoSection>, Vec<String>) {
    let mut repos = Vec::new();
    let mut other_work = Vec::new();
    let mut current_repo: Option<RepoSection> = None;
    let mut in_prs = false;
    let mut in_other_work = false;

    for line in body.lines() {
        let trimmed = line.trim();

        // H2 heading = repo name or "Other Work"
        if let Some(heading) = trimmed.strip_prefix("## ") {
            // Save previous repo
            if let Some(repo) = current_repo.take() {
                repos.push(repo);
            }
            in_prs = false;

            if heading == "Other Work" {
                in_other_work = true;
                continue;
            }

            in_other_work = false;
            current_repo = Some(RepoSection {
                name: heading.to_string(),
                lines_added: 0,
                lines_removed: 0,
                accomplishments: Vec::new(),
                pull_requests: Vec::new(),
            });
            continue;
        }

        // H3 heading = "Pull Requests" subsection
        if trimmed.starts_with("### Pull Requests") {
            in_prs = true;
            continue;
        }

        // Lines diff stats: _+716 -131_
        if trimmed.starts_with("_+") && trimmed.ends_with('_') {
            if let Some(ref mut repo) = current_repo {
                let inner = &trimmed[1..trimmed.len() - 1];
                let parts: Vec<&str> = inner.split_whitespace().collect();
                if parts.len() == 2 {
                    repo.lines_added = parts[0].trim_start_matches('+').parse().unwrap_or(0);
                    repo.lines_removed = parts[1].trim_start_matches('-').parse().unwrap_or(0);
                }
            }
            continue;
        }

        // Bullet points
        if let Some(bullet_content) = trimmed.strip_prefix("- ") {
            if in_other_work {
                other_work.push(bullet_content.to_string());
            } else if in_prs {
                if let Some(ref mut repo) = current_repo {
                    if let Some(pr) = parse_pr_line(bullet_content) {
                        repo.pull_requests.push(pr);
                    }
                }
            } else if let Some(ref mut repo) = current_repo {
                repo.accomplishments.push(bullet_content.to_string());
            }
        }
    }

    // Don't forget last repo
    if let Some(repo) = current_repo {
        repos.push(repo);
    }

    (repos, other_work)
}

/// Parse a PR line like: **Settings page rebuild** #142 — merged
fn parse_pr_line(line: &str) -> Option<JournalPR> {
    // Pattern: **title** #number — status
    let bold_start = line.find("**")?;
    let bold_end = line[bold_start + 2..].find("**")? + bold_start + 2;
    let title = line[bold_start + 2..bold_end].to_string();

    let rest = &line[bold_end + 2..];
    let hash_pos = rest.find('#')?;
    let after_hash = &rest[hash_pos + 1..];

    // Find the number (digits until non-digit)
    let num_end = after_hash.find(|c: char| !c.is_ascii_digit()).unwrap_or(after_hash.len());
    let number: u64 = after_hash[..num_end].parse().ok()?;

    // Find status after — or -
    let status = if let Some(dash_pos) = rest.find('—').or_else(|| rest.find(" - ")) {
        let s = rest[dash_pos..].trim_start_matches('—').trim_start_matches(" - ").trim();
        s.to_string()
    } else {
        "open".to_string()
    };

    Some(JournalPR {
        title,
        number,
        status,
        additions: 0,
        deletions: 0,
        url: String::new(),
    })
}

/// Render a JournalEntry as a markdown string.
pub fn render_markdown(entry: &JournalEntry) -> String {
    let mut out = String::new();

    // Frontmatter
    out.push_str("---\n");
    out.push_str(&format!("date: {}\n", entry.date));
    out.push_str(&format!("generated_at: {}\n", entry.generated_at));

    // Repos list
    out.push_str("repos:\n");
    for repo in &entry.repos {
        out.push_str(&format!("  - {}\n", repo.name));
    }

    // Stats
    out.push_str("stats:\n");
    out.push_str(&format!("  lines_changed: {}\n", entry.stats.lines_changed));
    out.push_str(&format!("  sessions: {}\n", entry.stats.sessions));
    out.push_str(&format!("  prs: {}\n", entry.stats.prs));
    out.push_str(&format!("  ai_authored_pct: {}\n", entry.stats.ai_authored_pct));
    out.push_str(&format!("  tokens: {}\n", entry.stats.tokens));
    out.push_str("---\n\n");

    // Repo sections
    for repo in &entry.repos {
        out.push_str(&format!("## {}\n", repo.name));
        out.push_str(&format!("_+{} -{}_ \n\n", repo.lines_added, repo.lines_removed));

        for item in &repo.accomplishments {
            out.push_str(&format!("- {}\n", item));
        }

        if !repo.pull_requests.is_empty() {
            out.push_str("\n### Pull Requests\n");
            for pr in &repo.pull_requests {
                out.push_str(&format!("- **{}** #{} — {}\n", pr.title, pr.number, pr.status));
            }
        }

        out.push('\n');
    }

    // Other work
    if !entry.other_work.is_empty() {
        out.push_str("## Other Work\n");
        for item in &entry.other_work {
            out.push_str(&format!("- {}\n", item));
        }
    }

    out
}

pub(crate) fn current_date() -> String {
    let now = std::time::SystemTime::now()
        .duration_since(std::time::UNIX_EPOCH)
        .unwrap_or_default()
        .as_secs();
    format_unix_date(now as i64)
}

pub fn format_unix_date(secs: i64) -> String {
    // Simple date formatting from unix timestamp
    let days = secs / 86400;
    let (year, month, day) = days_to_ymd(days);
    format!("{:04}-{:02}-{:02}", year, month, day)
}

pub(crate) fn subtract_days(date: &str, n: i64) -> String {
    // Parse YYYY-MM-DD, subtract n days, return YYYY-MM-DD
    let parts: Vec<i64> = date.split('-').filter_map(|p| p.parse().ok()).collect();
    if parts.len() != 3 {
        return date.to_string();
    }
    let total_days = ymd_to_days(parts[0], parts[1], parts[2]) - n;
    let (y, m, d) = days_to_ymd(total_days);
    format!("{:04}-{:02}-{:02}", y, m, d)
}

fn ymd_to_days(year: i64, month: i64, day: i64) -> i64 {
    let mut days: i64 = 0;
    for y in 1970..year {
        days += if is_leap(y) { 366 } else { 365 };
    }
    let month_lengths = [0, 31, 28, 31, 30, 31, 30, 31, 31, 30, 31, 30, 31];
    for m in 1..month {
        days += month_lengths[m as usize];
        if m == 2 && is_leap(year) {
            days += 1;
        }
    }
    days + day - 1
}

fn days_to_ymd(mut days: i64) -> (i64, i64, i64) {
    let mut year = 1970;
    loop {
        let year_days = if is_leap(year) { 366 } else { 365 };
        if days < year_days {
            break;
        }
        days -= year_days;
        year += 1;
    }
    let month_lengths = if is_leap(year) {
        [31, 29, 31, 30, 31, 30, 31, 31, 30, 31, 30, 31]
    } else {
        [31, 28, 31, 30, 31, 30, 31, 31, 30, 31, 30, 31]
    };
    let mut month = 1;
    for &ml in &month_lengths {
        if days < ml {
            break;
        }
        days -= ml;
        month += 1;
    }
    (year, month, days + 1)
}

fn is_leap(y: i64) -> bool {
    y % 4 == 0 && (y % 100 != 0 || y % 400 == 0)
}

#[cfg(test)]
mod tests {
    use super::*;

    #[test]
    fn roundtrip_markdown() {
        let entry = JournalEntry {
            date: "2026-03-20".to_string(),
            generated_at: "2026-03-20T17:42:00Z".to_string(),
            repos: vec![RepoSection {
                name: "entire-app".to_string(),
                lines_added: 716,
                lines_removed: 131,
                accomplishments: vec![
                    "Rebuilt settings page as a modal dialog".to_string(),
                    "Fixed terminal resize handle drag".to_string(),
                ],
                pull_requests: vec![JournalPR {
                    title: "Settings page rebuild".to_string(),
                    number: 142,
                    status: "merged".to_string(),
                    additions: 312,
                    deletions: 89,
                    url: String::new(),
                }],
            }],
            other_work: vec!["Led sprint planning".to_string()],
            stats: JournalStats {
                lines_changed: 847,
                sessions: 4,
                prs: 3,
                ai_authored_pct: 68,
                tokens: 12300,
            },
        };

        let md = render_markdown(&entry);
        let parsed = parse_markdown(&md).unwrap();

        assert_eq!(parsed.date, "2026-03-20");
        assert_eq!(parsed.repos.len(), 1);
        assert_eq!(parsed.repos[0].name, "entire-app");
        assert_eq!(parsed.repos[0].lines_added, 716);
        assert_eq!(parsed.repos[0].accomplishments.len(), 2);
        assert_eq!(parsed.repos[0].pull_requests.len(), 1);
        assert_eq!(parsed.repos[0].pull_requests[0].number, 142);
        assert_eq!(parsed.other_work.len(), 1);
        assert_eq!(parsed.stats.lines_changed, 847);
    }

    #[test]
    fn parse_pr_line_works() {
        let pr = parse_pr_line("**Fix terminal resize** #141 — merged").unwrap();
        assert_eq!(pr.title, "Fix terminal resize");
        assert_eq!(pr.number, 141);
        assert_eq!(pr.status, "merged");
    }

    #[test]
    fn subtract_days_works() {
        assert_eq!(subtract_days("2026-03-20", 1), "2026-03-19");
        assert_eq!(subtract_days("2026-03-01", 1), "2026-02-28");
        assert_eq!(subtract_days("2026-01-01", 1), "2025-12-31");
    }

    #[test]
    fn parse_empty_body() {
        let (repos, other) = parse_body("");
        assert!(repos.is_empty());
        assert!(other.is_empty());
    }
}

