#[derive(serde::Serialize)]
struct FileDiff {
    path: String,
    status: String, // "added", "modified", "deleted"
    hunks: Vec<DiffHunk>,
}

#[derive(serde::Serialize)]
struct DiffHunk {
    header: String,
    lines: Vec<DiffLine>,
}

#[derive(serde::Serialize)]
struct DiffLine {
    kind: String, // "add", "delete", "context"
    content: String,
    old_lineno: Option<u32>,
    new_lineno: Option<u32>,
}

#[derive(serde::Deserialize)]
struct CheckpointReviewMetadata {
