  return useMutation<void, Error, string>({
    mutationFn: (path: string) => invoke("block_repo", { path }),
    onSuccess: () => {
      queryClient.invalidateQueries({ queryKey: ["repos"] });
    },
  });
}

export function useCreateWorktreeMutation() {
  const queryClient = useQueryClient();
  return useMutation<void, Error, { repoPath: string; options: CreateWorktreeOptions }>({
    mutationFn: ({ repoPath, options }) =>
      invoke("create_worktree", {
        repoPath,
        mode: options.mode,
        branchName: options.branchName,
        targetPath: options.targetPath,
      }),
    onSuccess: () => {
      queryClient.invalidateQueries({ queryKey: ["repos"] });
    },
  });
}

export function useDeleteWorktreeMutation() {
  const queryClient = useQueryClient();
  return useMutation<void, Error, { repoPath: string; options: DeleteWorktreeOptions }>({
    mutationFn: ({ repoPath, options }) =>
      invoke("delete_worktree", {
        repoPath,
        worktreePath: options.worktreePath,
        branchName: options.branchName,
        force: options.force,
      }),
    onSuccess: () => {
      queryClient.invalidateQueries({ queryKey: ["repos"] });
    },
  });
}

export function useDeleteBranchMutation() {
  const queryClient = useQueryClient();
  return useMutation<void, Error, { repoPath: string; branchName: string }>({
    mutationFn: ({ repoPath, branchName }) =>
      invoke("delete_branch", {
        repoPath,
        branchName,
      }),
    onSuccess: () => {
      queryClient.invalidateQueries({ queryKey: ["repos"] });
    },
  });
}

export function useBranchTranscriptsQuery(
  repoPath: string,
  branch: string,
  enabled: boolean
) {
  const { data: checkpoints } = useCheckpointsQuery(repoPath, branch);

  const queries = useQueries({
    queries: (checkpoints ?? []).map((cp) => ({
      queryKey: ["transcript", repoPath, cp.checkpoint_id, 0] as const,
      queryFn: () =>
        invoke<TranscriptMessage[]>("get_transcript", {
          repoPath,
          checkpointId: cp.checkpoint_id,
          sessionIndex: 0,
        }),
      enabled: enabled && !!repoPath && !!cp.checkpoint_id,
      retry: false,
    })),
  });

  return { checkpoints: checkpoints ?? [], queries };
}

export function useJournalEntriesQuery(repoPath: string) {
  return useQuery<JournalEntry[]>({
    queryKey: ["journal-entries", repoPath],
    queryFn: () => invoke("list_journal_entries", { repoPath, limit: 100 }),
    enabled: !!repoPath,
    retry: false,
  });
}

export function useJournalDatesQuery(repoPath: string) {
  return useQuery<JournalDateInfo[]>({
    queryKey: ["journal-dates", repoPath],
    queryFn: () => invoke("get_journal_dates", { repoPath, limit: 100 }),
    enabled: !!repoPath,
    retry: false,
  });
}

export function useGenerateJournalMutation() {
  const queryClient = useQueryClient();
  return useMutation<JournalEntry, Error, { repoPath: string; date: string; extraItems?: string[] }>({
    mutationFn: ({ repoPath, date, extraItems }) =>
      invoke("generate_journal_entry", { repoPath, date, extraItems }),
    onSuccess: (_data, variables) => {
      queryClient.invalidateQueries({ queryKey: ["journal-entries", variables.repoPath] });
      queryClient.invalidateQueries({ queryKey: ["journal-dates", variables.repoPath] });
    },
  });
}

