                  </div>

                  {/* Checkpoint list resize handle */}
                  {selectedCheckpoint && (
                    <div
                      onMouseDown={handleCheckpointListResizeStart}
                      className="w-[3px] shrink-0 cursor-col-resize bg-border transition-colors hover:bg-accent"
                    />
                  )}

                  {/* Checkpoint detail panel */}
                  {selectedCheckpoint && (
                    <div className="flex flex-1 flex-col overflow-hidden">
                      {/* Detail header */}
                      <div className="flex items-center gap-3 border-b border-border-subtle px-4 py-2.5">
                        <button
