  1→use serde::{Deserialize, Serialize};
  2→use std::collections::HashSet;
  3→use std::fs;
  4→use std::path::{Path, PathBuf};
  5→
  6→#[derive(Debug, Serialize, Deserialize, Clone, Default)]
  7→pub struct EntireSettings {
  8→    pub enabled: Option<bool>,
  9→    pub local_dev: Option<bool>,
 10→    pub log_level: Option<String>,
 11→    pub telemetry: Option<bool>,
 12→}
 13→
 14→/// Read .entire/settings.json from a repo
 15→pub fn read_settings(repo_path: &str) -> Result<EntireSettings, String> {
 16→    let settings_path = Path::new(repo_path).join(".entire/settings.json");
 17→    if !settings_path.exists() {
 18→        return Err("No .entire/settings.json found".to_string());
 19→    }
 20→
 21→    let content =
 22→        fs::read_to_string(&settings_path).map_err(|e| format!("Failed to read settings: {}", e))?;
 23→
 24→    serde_json::from_str(&content).map_err(|e| format!("Failed to parse settings: {}", e))
 25→}
 26→
 27→/// Check if a repo has Entire enabled
 28→pub fn is_entire_enabled(repo_path: &str) -> bool {
 29→    let entire_dir = Path::new(repo_path).join(".entire");
 30→    if !entire_dir.exists() {
 31→        return false;
 32→    }
 33→    match read_settings(repo_path) {
 34→        Ok(settings) => settings.enabled.unwrap_or(false),
 35→        Err(_) => false,
 36→    }
 37→}
