511→fn load_sanitized_checkpoint_transcripts(
512→    repo: &git2::Repository,
513→    checkpoint_id: &str,
514→) -> Result<Vec<semantic_review::PromptTranscriptSession>, String> {
515→    let prefix = &checkpoint_id[..2];
516→    let suffix = &checkpoint_id[2..];
517→    let meta_path = format!("{}/{}/metadata.json", prefix, suffix);
518→    let meta_content = read_blob(repo, &meta_path)?;
519→    let meta = serde_json::from_str::<CheckpointReviewMetadata>(&meta_content)
520→        .map_err(|e| format!("Failed to parse checkpoint metadata: {}", e))?;
521→
522→    let session_count = meta.sessions.map(|sessions| sessions.len()).unwrap_or(0);
523→    let mut all_sessions = Vec::new();
524→
525→    for session_index in 0..session_count {
526→        let candidates =
527→            transcript_candidate_paths(checkpoint_id, session_index as u32, Some(&meta_content));
528→        let mut transcript_content = None;
529→        for path in candidates {
530→            if let Ok(content) = read_blob(repo, &path) {
531→                transcript_content = Some(content);
532→                break;
533→            }
534→        }
535→
536→        let Some(content) = transcript_content else {
537→            continue;
538→        };
539→
540→        let parsed = session::read_transcript(&content);
541→        let sanitized = session::sanitize_transcript_for_semantic_review(&parsed, 4_000);
542→        if sanitized.is_empty() {
543→            continue;
544→        }
545→
546→        all_sessions.push(semantic_review::PromptTranscriptSession {
547→            session_index: session_index as u32,
548→            messages: sanitized
549→                .into_iter()
550→                .map(|message| semantic_review::PromptTranscriptMessage {
551→                    role: message.role,
552→                    content: message.content,
553→                })
554→                .collect(),
555→        });
556→    }
557→
558→    Ok(all_sessions)
559→}
