359→/// Render a JournalEntry as a markdown string.
360→pub fn render_markdown(entry: &JournalEntry) -> String {
361→    let mut out = String::new();
362→
363→    // Frontmatter
364→    out.push_str("---\n");
365→    out.push_str(&format!("date: {}\n", entry.date));
366→    out.push_str(&format!("generated_at: {}\n", entry.generated_at));
367→
368→    // Repos list
369→    out.push_str("repos:\n");
370→    for repo in &entry.repos {
371→        out.push_str(&format!("  - {}\n", repo.name));
372→    }
373→
374→    // Stats
375→    out.push_str("stats:\n");
376→    out.push_str(&format!("  lines_changed: {}\n", entry.stats.lines_changed));
377→    out.push_str(&format!("  sessions: {}\n", entry.stats.sessions));
378→    out.push_str(&format!("  prs: {}\n", entry.stats.prs));
379→    out.push_str(&format!("  ai_authored_pct: {}\n", entry.stats.ai_authored_pct));
380→    out.push_str(&format!("  tokens: {}\n", entry.stats.tokens));
381→    out.push_str("---\n\n");
382→
383→    // Repo sections
384→    for repo in &entry.repos {
385→        out.push_str(&format!("## {}\n", repo.name));
386→        out.push_str(&format!("_+{} -{}_ \n\n", repo.lines_added, repo.lines_removed));
387→
388→        for item in &repo.accomplishments {
389→            out.push_str(&format!("- {}\n", item));
390→        }
391→
392→        if !repo.pull_requests.is_empty() {
393→            out.push_str("\n### Pull Requests\n");
394→            for pr in &repo.pull_requests {
395→                out.push_str(&format!("- **{}** #{} — {}\n", pr.title, pr.number, pr.status));
396→            }
397→        }
398→
399→        out.push('\n');
400→    }
401→
402→    // Other work
403→    if !entry.other_work.is_empty() {
404→        out.push_str("## Other Work\n");
405→        for item in &entry.other_work {
406→            out.push_str(&format!("- {}\n", item));
407→        }
408→    }
409→
410→    out
411→}
