  6→/// Parse a GitHub owner/repo from a git remote URL.
  7→/// Handles: https://github.com/owner/repo.git, git@github.com:owner/repo.git
  8→pub fn parse_github_remote(remote_url: &str) -> Option<(String, String)> {
  9→    let url = remote_url.trim().trim_end_matches(".git");
 10→
 11→    // SSH: git@github.com:owner/repo
 12→    if let Some(rest) = url.strip_prefix("git@github.com:") {
 13→        let parts: Vec<&str> = rest.splitn(2, '/').collect();
 14→        if parts.len() == 2 {
 15→            return Some((parts[0].to_string(), parts[1].to_string()));
 16→        }
 17→    }
 18→
 19→    // HTTPS: https://github.com/owner/repo
 20→    if url.contains("github.com/") {
 21→        let after = url.split("github.com/").nth(1)?;
 22→        let parts: Vec<&str> = after.splitn(2, '/').collect();
 23→        if parts.len() == 2 {
 24→            return Some((parts[0].to_string(), parts[1].to_string()));
 25→        }
 26→    }
 27→
 28→    None
 29→}
