 31→/// Get the origin remote URL for a repo using git CLI.
 32→pub fn get_remote_url(repo_path: &str) -> Option<String> {
 33→    let output = Command::new("git")
 34→        .args(["remote", "get-url", "origin"])
 35→        .current_dir(repo_path)
 36→        .output()
 37→        .ok()?;
 38→
 39→    if output.status.success() {
 40→        Some(String::from_utf8_lossy(&output.stdout).trim().to_string())
 41→    } else {
 42→        None
 43→    }
 44→}
 45→
 46→/// Get a GitHub token from env var or gh CLI.
 47→fn get_github_token() -> Option<String> {
 48→    if let Ok(token) = std::env::var("GITHUB_TOKEN") {
 49→        if !token.is_empty() {
 50→            return Some(token);
 51→        }
 52→    }
 53→
 54→    // Fall back to gh CLI
 55→    let output = Command::new("gh")
 56→        .args(["auth", "token"])
 57→        .output()
 58→        .ok()?;
 59→
 60→    if output.status.success() {
 61→        let token = String::from_utf8_lossy(&output.stdout).trim().to_string();
 62→        if !token.is_empty() {
 63→            return Some(token);
 64→        }
 65→    }
 66→
 67→    None
 68→}
