 89→/// Fetch PRs for a repo that were updated on a given date.
 90→/// Returns empty vec if no GitHub token is available (graceful degradation).
 91→pub fn fetch_prs_for_date(
 92→    repo_path: &str,
 93→    date: &str,
 94→) -> Vec<JournalPR> {
 95→    let remote_url = match get_remote_url(repo_path) {
 96→        Some(url) => url,
 97→        None => return Vec::new(),
 98→    };
 99→
100→    let (owner, repo) = match parse_github_remote(&remote_url) {
101→        Some(pair) => pair,
102→        None => return Vec::new(),
103→    };
104→
105→    let token = match get_github_token() {
106→        Some(t) => t,
107→        None => return Vec::new(),
108→    };
109→
110→    let query = format!("repo:{}/{} is:pr updated:{}", owner, repo, date);
111→    let url = format!(
112→        "https://api.github.com/search/issues?q={}&per_page=100",
113→        urlencoded(&query)
114→    );
115→
116→    let client = match reqwest::blocking::Client::builder()
117→        .timeout(std::time::Duration::from_secs(15))
118→        .build()
119→    {
120→        Ok(c) => c,
121→        Err(_) => return Vec::new(),
122→    };
123→
124→    let response = client
125→        .get(&url)
126→        .header("Authorization", format!("Bearer {}", token))
127→        .header("Accept", "application/vnd.github+json")
128→        .header("User-Agent", "entire-desktop")
129→        .header("X-GitHub-Api-Version", "2022-11-28")
130→        .send();
131→
132→    let response = match response {
133→        Ok(r) => r,
134→        Err(e) => {
135→            eprintln!("GitHub API error: {}", e);
136→            return Vec::new();
137→        }
138→    };
139→
140→    if !response.status().is_success() {
141→        eprintln!("GitHub API returned status: {}", response.status());
142→        return Vec::new();
143→    }
144→
145→    let search: SearchResponse = match response.json() {
146→        Ok(s) => s,
147→        Err(e) => {
148→            eprintln!("Failed to parse GitHub response: {}", e);
149→            return Vec::new();
150→        }
151→    };
152→
153→    search
154→        .items
155→        .into_iter()
156→        .map(|item| {
157→            let status = if item.pull_request
158→                .as_ref()
159→                .and_then(|pr| pr.merged_at.as_ref())
160→                .is_some()
161→            {
162→                "merged".to_string()
163→            } else if item.state == "closed" {
164→                "closed".to_string()
165→            } else {
166→                "open".to_string()
167→            };
168→
169→            JournalPR {
170→                title: item.title,
171→                number: item.number,
172→                status,
173→                additions: 0,
174→                deletions: 0,
175→                url: item.html_url,
176→            }
177→        })
178→        .collect()
179→}
180→
181→fn urlencoded(s: &str) -> String {
182→    s.replace(' ', "+")
183→        .replace(':', "%3A")
184→        .replace('/', "%2F")
185→}
