 52→/// Get the global journal directory (~/.entire/journal/), creating it if needed.
 53→pub fn journal_dir() -> PathBuf {
 54→    let home = std::env::var("HOME").unwrap_or_default();
 55→    let dir = Path::new(&home).join(".entire/journal");
 56→    let _ = fs::create_dir_all(&dir);
 57→    dir
 58→}
