 60→/// List journal entries from markdown files, sorted newest first.
 61→/// `limit` defaults to 100.
 62→pub fn list_entries(limit: usize) -> Result<Vec<JournalEntry>, String> {
 63→    let dir = journal_dir();
 64→    if !dir.exists() {
 65→        return Ok(Vec::new());
 66→    }
 67→
 68→    let mut files: Vec<_> = fs::read_dir(&dir)
 69→        .map_err(|e| format!("Failed to read journal dir: {}", e))?
 70→        .filter_map(|e| e.ok())
 71→        .filter(|e| {
 72→            e.path()
 73→                .extension()
 74→                .map_or(false, |ext| ext == "md")
 75→        })
 76→        .collect();
 77→
 78→    // Sort by filename descending (YYYY-MM-DD.md sorts chronologically)
 79→    files.sort_by(|a, b| b.file_name().cmp(&a.file_name()));
 80→    files.truncate(limit);
 81→
 82→    let mut entries = Vec::new();
 83→    for file in files {
 84→        let content = fs::read_to_string(file.path())
 85→            .map_err(|e| format!("Failed to read {}: {}", file.path().display(), e))?;
 86→        match parse_markdown(&content) {
 87→            Ok(entry) => entries.push(entry),
 88→            Err(e) => eprintln!("Skipping {}: {}", file.path().display(), e),
 89→        }
 90→    }
 91→
 92→    Ok(entries)
 93→}
