 95→/// Get a single journal entry by date (YYYY-MM-DD).
 96→pub fn get_entry(date: &str) -> Result<JournalEntry, String> {
 97→    let path = journal_dir().join(format!("{}.md", date));
 98→    if !path.exists() {
 99→        return Err(format!("No journal entry for {}", date));
100→    }
101→    let content = fs::read_to_string(&path)
102→        .map_err(|e| format!("Failed to read entry: {}", e))?;
103→    parse_markdown(&content)
104→}
