106→/// Get date info for the date jumper rail.
107→pub fn list_dates(limit: usize) -> Result<Vec<JournalDateInfo>, String> {
108→    let dir = journal_dir();
109→
110→    // Build a set of dates that have entries
111→    let mut entry_dates = std::collections::HashSet::new();
112→    let mut stats_map = std::collections::HashMap::new();
113→
114→    if dir.exists() {
115→        if let Ok(read_dir) = fs::read_dir(&dir) {
116→            for entry in read_dir.filter_map(|e| e.ok()) {
117→                let path = entry.path();
118→                if path.extension().map_or(false, |ext| ext == "md") {
119→                    if let Some(stem) = path.file_stem().and_then(|s| s.to_str()) {
120→                        entry_dates.insert(stem.to_string());
121→                        // Quick parse frontmatter for stats
122→                        if let Ok(content) = fs::read_to_string(&path) {
123→                            if let Ok(parsed) = parse_frontmatter_only(&content) {
124→                                stats_map.insert(stem.to_string(), parsed);
125→                            }
126→                        }
127→                    }
128→                }
129→            }
130→        }
131→    }
132→
133→    // Generate last `limit` days
134→    let today = current_date();
135→    let mut dates = Vec::new();
136→    for i in 0..limit {
137→        let date = subtract_days(&today, i as i64);
138→        let has_entry = entry_dates.contains(&date);
139→        let activity_level = stats_map
140→            .get(&date)
141→            .map(|s| {
142→                // Scale lines_changed to 0-4
143→                match s.lines_changed {
144→                    0 => 0,
145→                    1..=100 => 1,
146→                    101..=500 => 2,
147→                    501..=1000 => 3,
148→                    _ => 4,
149→                }
150→            })
151→            .unwrap_or(0);
152→
153→        dates.push(JournalDateInfo {
154→            date,
155→            has_entry,
156→            activity_level,
157→        });
158→    }
159→
160→    Ok(dates)
161→}
