163→/// Save a journal entry as a markdown file.
164→pub fn save_entry(entry: &JournalEntry) -> Result<(), String> {
165→    let dir = journal_dir();
166→    let path = dir.join(format!("{}.md", entry.date));
167→    let content = render_markdown(entry);
168→    fs::write(&path, content)
169→        .map_err(|e| format!("Failed to write journal entry: {}", e))
170→}
