172→/// Parse a journal markdown file into a JournalEntry.
173→pub fn parse_markdown(content: &str) -> Result<JournalEntry, String> {
174→    // Split frontmatter from body
175→    let (frontmatter, body) = split_frontmatter(content)?;
176→
177→    // Parse YAML frontmatter
178→    let date = extract_yaml_field(&frontmatter, "date")
179→        .ok_or("Missing date in frontmatter")?;
180→    let generated_at = extract_yaml_field(&frontmatter, "generated_at")
181→        .unwrap_or_default();
182→    let stats = parse_frontmatter_only(content)?;
183→
184→    // Parse body into repo sections and other work
185→    let (repos, other_work) = parse_body(&body);
186→
187→    Ok(JournalEntry {
188→        date,
189→        generated_at,
190→        repos,
191→        other_work,
192→        stats,
193→    })
194→}
195→
196→fn split_frontmatter(content: &str) -> Result<(String, String), String> {
197→    let content = content.trim();
198→    if !content.starts_with("---") {
199→        return Err("No frontmatter found".to_string());
200→    }
201→    let rest = &content[3..];
202→    let end = rest.find("---").ok_or("Unterminated frontmatter")?;
203→    let frontmatter = rest[..end].trim().to_string();
204→    let body = rest[end + 3..].trim().to_string();
205→    Ok((frontmatter, body))
206→}
207→
208→fn extract_yaml_field(yaml: &str, field: &str) -> Option<String> {
209→    for line in yaml.lines() {
210→        let line = line.trim();
211→        if let Some(rest) = line.strip_prefix(&format!("{}:", field)) {
212→            let value = rest.trim().trim_matches('"').trim_matches('\'');
213→            if !value.is_empty() {
214→                return Some(value.to_string());
215→            }
216→        }
217→    }
218→    None
219→}
220→
221→fn parse_frontmatter_only(content: &str) -> Result<JournalStats, String> {
222→    let (frontmatter, _) = split_frontmatter(content)?;
223→
224→    let lines_changed = extract_yaml_field(&frontmatter, "lines_changed")
225→        .and_then(|v| v.parse().ok())
226→        .unwrap_or(0);
227→    let sessions = extract_yaml_field(&frontmatter, "sessions")
228→        .and_then(|v| v.parse().ok())
229→        .unwrap_or(0);
230→    let prs = extract_yaml_field(&frontmatter, "prs")
231→        .and_then(|v| v.parse().ok())
232→        .unwrap_or(0);
233→    let ai_authored_pct = extract_yaml_field(&frontmatter, "ai_authored_pct")
234→        .and_then(|v| v.parse().ok())
235→        .unwrap_or(0);
236→    let tokens = extract_yaml_field(&frontmatter, "tokens")
237→        .and_then(|v| v.parse().ok())
238→        .unwrap_or(0);
239→
240→    Ok(JournalStats {
241→        lines_changed,
242→        sessions,
243→        prs,
244→        ai_authored_pct,
245→        tokens,
246→    })
247→}
248→
249→fn parse_body(body: &str) -> (Vec<RepoSection>, Vec<String>) {
250→    let mut repos = Vec::new();
251→    let mut other_work = Vec::new();
252→    let mut current_repo: Option<RepoSection> = None;
253→    let mut in_prs = false;
254→    let mut in_other_work = false;
255→
256→    for line in body.lines() {
257→        let trimmed = line.trim();
258→
259→        // H2 heading = repo name or "Other Work"
260→        if let Some(heading) = trimmed.strip_prefix("## ") {
261→            // Save previous repo
262→            if let Some(repo) = current_repo.take() {
263→                repos.push(repo);
264→            }
265→            in_prs = false;
266→
267→            if heading == "Other Work" {
268→                in_other_work = true;
269→                continue;
270→            }
271→
272→            in_other_work = false;
273→            current_repo = Some(RepoSection {
274→                name: heading.to_string(),
275→                lines_added: 0,
276→                lines_removed: 0,
277→                accomplishments: Vec::new(),
278→                pull_requests: Vec::new(),
279→            });
280→            continue;
281→        }
282→
283→        // H3 heading = "Pull Requests" subsection
284→        if trimmed.starts_with("### Pull Requests") {
285→            in_prs = true;
286→            continue;
287→        }
288→
289→        // Lines diff stats: _+716 -131_
290→        if trimmed.starts_with("_+") && trimmed.ends_with('_') {
291→            if let Some(ref mut repo) = current_repo {
292→                let inner = &trimmed[1..trimmed.len() - 1];
293→                let parts: Vec<&str> = inner.split_whitespace().collect();
294→                if parts.len() == 2 {
295→                    repo.lines_added = parts[0].trim_start_matches('+').parse().unwrap_or(0);
296→                    repo.lines_removed = parts[1].trim_start_matches('-').parse().unwrap_or(0);
297→                }
298→            }
299→            continue;
300→        }
301→
302→        // Bullet points
303→        if let Some(bullet_content) = trimmed.strip_prefix("- ") {
304→            if in_other_work {
305→                other_work.push(bullet_content.to_string());
306→            } else if in_prs {
307→                if let Some(ref mut repo) = current_repo {
308→                    if let Some(pr) = parse_pr_line(bullet_content) {
309→                        repo.pull_requests.push(pr);
310→                    }
311→                }
312→            } else if let Some(ref mut repo) = current_repo {
313→                repo.accomplishments.push(bullet_content.to_string());
314→            }
315→        }
316→    }
317→
318→    // Don't forget last repo
319→    if let Some(repo) = current_repo {
320→        repos.push(repo);
321→    }
322→
323→    (repos, other_work)
324→}
325→
326→/// Parse a PR line like: **Settings page rebuild** #142 — merged
327→fn parse_pr_line(line: &str) -> Option<JournalPR> {
328→    // Pattern: **title** #number — status
329→    let bold_start = line.find("**")?;
330→    let bold_end = line[bold_start + 2..].find("**")? + bold_start + 2;
331→    let title = line[bold_start + 2..bold_end].to_string();
332→
333→    let rest = &line[bold_end + 2..];
334→    let hash_pos = rest.find('#')?;
335→    let after_hash = &rest[hash_pos + 1..];
336→
337→    // Find the number (digits until non-digit)
338→    let num_end = after_hash.find(|c: char| !c.is_ascii_digit()).unwrap_or(after_hash.len());
339→    let number: u64 = after_hash[..num_end].parse().ok()?;
340→
341→    // Find status after — or -
342→    let status = if let Some(dash_pos) = rest.find('—').or_else(|| rest.find(" - ")) {
343→        let s = rest[dash_pos..].trim_start_matches('—').trim_start_matches(" - ").trim();
344→        s.to_string()
345→    } else {
346→        "open".to_string()
347→    };
348→
349→    Some(JournalPR {
350→        title,
351→        number,
352→        status,
353→        additions: 0,
354→        deletions: 0,
355→        url: String::new(),
356→    })
357→}
358→
359→/// Render a JournalEntry as a markdown string.
360→pub fn render_markdown(entry: &JournalEntry) -> String {
361→    let mut out = String::new();
362→
363→    // Frontmatter
364→    out.push_str("---\n");
365→    out.push_str(&format!("date: {}\n", entry.date));
366→    out.push_str(&format!("generated_at: {}\n", entry.generated_at));
367→
368→    // Repos list
369→    out.push_str("repos:\n");
370→    for repo in &entry.repos {
371→        out.push_str(&format!("  - {}\n", repo.name));
372→    }
373→
374→    // Stats
375→    out.push_str("stats:\n");
376→    out.push_str(&format!("  lines_changed: {}\n", entry.stats.lines_changed));
377→    out.push_str(&format!("  sessions: {}\n", entry.stats.sessions));
378→    out.push_str(&format!("  prs: {}\n", entry.stats.prs));
379→    out.push_str(&format!("  ai_authored_pct: {}\n", entry.stats.ai_authored_pct));
380→    out.push_str(&format!("  tokens: {}\n", entry.stats.tokens));
381→    out.push_str("---\n\n");
382→
383→    // Repo sections
384→    for repo in &entry.repos {
385→        out.push_str(&format!("## {}\n", repo.name));
386→        out.push_str(&format!("_+{} -{}_ \n\n", repo.lines_added, repo.lines_removed));
387→
388→        for item in &repo.accomplishments {
389→            out.push_str(&format!("- {}\n", item));
390→        }
391→
392→        if !repo.pull_requests.is_empty() {
393→            out.push_str("\n### Pull Requests\n");
394→            for pr in &repo.pull_requests {
395→                out.push_str(&format!("- **{}** #{} — {}\n", pr.title, pr.number, pr.status));
396→            }
397→        }
398→
399→        out.push('\n');
400→    }
401→
402→    // Other work
403→    if !entry.other_work.is_empty() {
404→        out.push_str("## Other Work\n");
405→        for item in &entry.other_work {
406→            out.push_str(&format!("- {}\n", item));
407→        }
408→    }
409→
410→    out
411→}
412→
413→pub(crate) fn current_date() -> String {
414→    let now = std::time::SystemTime::now()
415→        .duration_since(std::time::UNIX_EPOCH)
416→        .unwrap_or_default()
417→        .as_secs();
418→    format_unix_date(now as i64)
419→}
420→
421→pub fn format_unix_date(secs: i64) -> String {
422→    // Simple date formatting from unix timestamp
423→    let days = secs / 86400;
424→    let (year, month, day) = days_to_ymd(days);
425→    format!("{:04}-{:02}-{:02}", year, month, day)
426→}
427→
428→pub(crate) fn subtract_days(date: &str, n: i64) -> String {
429→    // Parse YYYY-MM-DD, subtract n days, return YYYY-MM-DD
430→    let parts: Vec<i64> = date.split('-').filter_map(|p| p.parse().ok()).collect();
431→    if parts.len() != 3 {
432→        return date.to_string();
433→    }
434→    let total_days = ymd_to_days(parts[0], parts[1], parts[2]) - n;
435→    let (y, m, d) = days_to_ymd(total_days);
436→    format!("{:04}-{:02}-{:02}", y, m, d)
437→}
438→
439→fn ymd_to_days(year: i64, month: i64, day: i64) -> i64 {
440→    let mut days: i64 = 0;
441→    for y in 1970..year {
442→        days += if is_leap(y) { 366 } else { 365 };
443→    }
444→    let month_lengths = [0, 31, 28, 31, 30, 31, 30, 31, 31, 30, 31, 30, 31];
445→    for m in 1..month {
446→        days += month_lengths[m as usize];
447→        if m == 2 && is_leap(year) {
448→            days += 1;
449→        }
450→    }
451→    days + day - 1
452→}
453→
454→fn days_to_ymd(mut days: i64) -> (i64, i64, i64) {
455→    let mut year = 1970;
456→    loop {
457→        let year_days = if is_leap(year) { 366 } else { 365 };
458→        if days < year_days {
459→            break;
460→        }
461→        days -= year_days;
462→        year += 1;
463→    }
464→    let month_lengths = if is_leap(year) {
465→        [31, 29, 31, 30, 31, 30, 31, 31, 30, 31, 30, 31]
466→    } else {
467→        [31, 28, 31, 30, 31, 30, 31, 31, 30, 31, 30, 31]
468→    };
469→    let mut month = 1;
470→    for &ml in &month_lengths {
471→        if days < ml {
472→            break;
473→        }
474→        days -= ml;
475→        month += 1;
476→    }
477→    (year, month, days + 1)
478→}
479→
480→fn is_leap(y: i64) -> bool {
481→    y % 4 == 0 && (y % 100 != 0 || y % 400 == 0)
482→}
