use serde::Deserialize;
use std::process::Command;

use super::JournalPR;

/// Parse a GitHub owner/repo from a git remote URL.
/// Handles: https://github.com/owner/repo.git, git@github.com:owner/repo.git
pub fn parse_github_remote(remote_url: &str) -> Option<(String, String)> {
    let url = remote_url.trim().trim_end_matches(".git");

    // SSH: git@github.com:owner/repo
    if let Some(rest) = url.strip_prefix("git@github.com:") {
        let parts: Vec<&str> = rest.splitn(2, '/').collect();
        if parts.len() == 2 {
            return Some((parts[0].to_string(), parts[1].to_string()));
        }
    }

    // HTTPS: https://github.com/owner/repo
    if url.contains("github.com/") {
        let after = url.split("github.com/").nth(1)?;
        let parts: Vec<&str> = after.splitn(2, '/').collect();
        if parts.len() == 2 {
            return Some((parts[0].to_string(), parts[1].to_string()));
        }
    }

    None
}

/// Get the origin remote URL for a repo using git CLI.
pub fn get_remote_url(repo_path: &str) -> Option<String> {
    let output = Command::new("git")
        .args(["remote", "get-url", "origin"])
        .current_dir(repo_path)
        .output()
        .ok()?;

    if output.status.success() {
        Some(String::from_utf8_lossy(&output.stdout).trim().to_string())
    } else {
        None
    }
}

/// Get a GitHub token from env var or gh CLI.
fn get_github_token() -> Option<String> {
    if let Ok(token) = std::env::var("GITHUB_TOKEN") {
        if !token.is_empty() {
            return Some(token);
        }
    }

    // Fall back to gh CLI
    let output = Command::new("gh")
        .args(["auth", "token"])
        .output()
        .ok()?;

    if output.status.success() {
        let token = String::from_utf8_lossy(&output.stdout).trim().to_string();
        if !token.is_empty() {
            return Some(token);
        }
    }

    None
}

#[derive(Debug, Deserialize)]
struct SearchResponse {
    items: Vec<SearchItem>,
}

#[derive(Debug, Deserialize)]
struct SearchItem {
    number: u64,
    title: String,
    html_url: String,
    state: String,
    pull_request: Option<PullRequestInfo>,
}

#[derive(Debug, Deserialize)]
struct PullRequestInfo {
    merged_at: Option<String>,
}

/// Fetch PRs for a repo that were updated on a given date.
/// Returns empty vec if no GitHub token is available (graceful degradation).
pub fn fetch_prs_for_date(
    repo_path: &str,
    date: &str,
) -> Vec<JournalPR> {
    let remote_url = match get_remote_url(repo_path) {
        Some(url) => url,
        None => return Vec::new(),
    };

    let (owner, repo) = match parse_github_remote(&remote_url) {
        Some(pair) => pair,
        None => return Vec::new(),
    };

    let token = match get_github_token() {
        Some(t) => t,
        None => return Vec::new(),
    };

    let query = format!("repo:{}/{} is:pr updated:{}", owner, repo, date);
    let url = format!(
        "https://api.github.com/search/issues?q={}&per_page=100",
        urlencoded(&query)
    );

    let client = match reqwest::blocking::Client::builder()
        .timeout(std::time::Duration::from_secs(15))
        .build()
    {
        Ok(c) => c,
        Err(_) => return Vec::new(),
    };

    let response = client
        .get(&url)
        .header("Authorization", format!("Bearer {}", token))
        .header("Accept", "application/vnd.github+json")
        .header("User-Agent", "entire-desktop")
        .header("X-GitHub-Api-Version", "2022-11-28")
        .send();

    let response = match response {
        Ok(r) => r,
        Err(e) => {
            eprintln!("GitHub API error: {}", e);
            return Vec::new();
        }
    };

    if !response.status().is_success() {
        eprintln!("GitHub API returned status: {}", response.status());
        return Vec::new();
    }

    let search: SearchResponse = match response.json() {
        Ok(s) => s,
        Err(e) => {
            eprintln!("Failed to parse GitHub response: {}", e);
            return Vec::new();
        }
    };

    search
        .items
        .into_iter()
        .map(|item| {
            let status = if item.pull_request
                .as_ref()
                .and_then(|pr| pr.merged_at.as_ref())
                .is_some()
            {
                "merged".to_string()
            } else if item.state == "closed" {
                "closed".to_string()
            } else {
                "open".to_string()
            };

            JournalPR {
                title: item.title,
                number: item.number,
                status,
                additions: 0,
                deletions: 0,
                url: item.html_url,
            }
        })
        .collect()
}

fn urlencoded(s: &str) -> String {
    s.replace(' ', "+")
        .replace(':', "%3A")
        .replace('/', "%2F")
}

#[cfg(test)]
mod tests {
    use super::*;

    #[test]
    fn parse_https_remote() {
        let (owner, repo) = parse_github_remote("https://github.com/alisha/entire-app.git").unwrap();
        assert_eq!(owner, "alisha");
        assert_eq!(repo, "entire-app");
    }

    #[test]
    fn parse_ssh_remote() {
        let (owner, repo) = parse_github_remote("git@github.com:alisha/entire-app.git").unwrap();
        assert_eq!(owner, "alisha");
        assert_eq!(repo, "entire-app");
    }

    #[test]
    fn parse_no_git_suffix() {
        let (owner, repo) = parse_github_remote("https://github.com/alisha/entire-app").unwrap();
        assert_eq!(owner, "alisha");
        assert_eq!(repo, "entire-app");
    }

    #[test]
    fn non_github_returns_none() {
        assert!(parse_github_remote("https://gitlab.com/foo/bar.git").is_none());
    }
}

import type { JournalRepoSection } from "../../lib/ipc";

interface RepoSectionProps {
  repo: JournalRepoSection;
}

export function RepoSection({ repo }: RepoSectionProps) {
  return (
    <div className="rounded-lg border border-border bg-bg-raised p-4">
      <div className="mb-2.5 flex items-center gap-2">
        <span className="text-[13px] font-semibold text-fg">{repo.name}</span>
        <span className="rounded-full bg-accent/10 px-1.5 py-0.5 text-[10px] text-accent">
          +{repo.lines_added} -{repo.lines_removed}
        </span>
      </div>

      <ul className="list-disc space-y-1 pl-5">
        {repo.accomplishments.map((item, i) => (
          <li key={i} className="text-xs leading-relaxed text-fg">
            {item}
          </li>
        ))}
      </ul>

      {repo.pull_requests.length > 0 && (
        <div className="mt-3 border-t border-border pt-2.5">
          <div className="space-y-1.5">
            {repo.pull_requests.map((pr) => (
              <div key={pr.number} className="flex items-center justify-between">
                <span className="text-[11px] text-fg">
                  {pr.url ? (
                    <a
                      href={pr.url}
                      target="_blank"
                      rel="noopener noreferrer"
                      className="hover:underline"
                    >
                      {pr.title}
                    </a>
                  ) : (
                    pr.title
                  )}
                  {" "}
                  <span className="text-fg-subtle">#{pr.number}</span>
                </span>
                <span
                  className={`rounded-full px-1.5 py-0.5 text-[10px] ${
                    pr.status === "merged"
