}
```

**`parse_pr_line()`** (line 327) — Parse the `[**title**](url)` format, falling back to `**title**` for old entries:
```rust
fn parse_pr_line(line: &str) -> Option<JournalPR> {
    let (title, url, rest) = if line.starts_with("[**") {
        // [**title**](url) #number — status
        let bold_end = line.find("**](")?;
